import { useState } from "react";

const NasaObj = (props) => {

  const [open, setOpen] = useState(false);

  const obj = props.apod;

  const openModal = () => {
    if (open) {
      setOpen(false);
    } else {
      setOpen(true);
    }
  }

  const closeModal = (e) => {
    if (!e.target.classList.contains('modal-img')) {
      setOpen(false);
    }
  }

  return (
    <>
      {obj.media_type === 'image' 
        ? <img className="apod-img" src={obj.url} alt={obj.title} onClick={() => openModal()}/>
        : <iframe className="apod-video" src={obj.url} />}
      <div className={open ? 'modal-overlay open' : 'modal-overlay'} onClick={closeModal}>
        <img src={obj.url} alt="" className="modal-img"/>
      </div>
    </>
  )
}

export default NasaObj
